export function updateFetchJobIndicator() {
  const el = $("fetchJobIndicator");
  const textEl = $("fetchJobIndicatorText");
  if (!el) return;

  const active = state.countryFetchActive || state.fetchBusy;
  if (!active) {
    el.hidden = true;
    return;
  }

  el.hidden = false;
  const summary = state.fetchJobSummary || {};
  let line = "Background job running";

  if (state.fetchBusy && state.fetchingCompanyKey) {
    const company = state.fetchingCompanyKey.split(":").slice(1).join(":");
    line = `Fetching ${company}`;
  } else if (summary.total > 0) {
    line = `Fetching ${summary.current}/${summary.total} companies`;
  } else if (summary.company) {
    line = `Fetching ${summary.company}`;
  } else if (summary.country) {
    line = `Fetching ${summary.countryLabel || summary.country}`;
  }

  if (textEl) textEl.textContent = line;
}

