export function updateFetchHeaderUI() {
  const fetchBtn = $("fetchCountryBtn");
  const chip = $("fetchProgressChip");
  const meta = $("fetchProgressChipMeta");
  const fill = $("fetchProgressChipFill");
  const companyEl = $("fetchProgressChipCompany");
  if (!fetchBtn || !chip) return;

  const controlsEnabled = Boolean(state.fetchControlsEnabled);
  const active = state.serverFetchRunning || state.countryFetchActive || state.fetchBusy;

  if (!controlsEnabled) {
    fetchBtn.hidden = true;
    chip.hidden = true;
    return;
  }

  if (!active) {
    fetchBtn.hidden = false;
    chip.hidden = true;
    fetchBtn.title = "Fetch jobs for the selected country and ATS filter";
    return;
  }

  fetchBtn.hidden = true;
  chip.hidden = false;

  const summary = state.fetchJobSummary || {};
  let metaText = "Starting…";
  let companyLine = "";
  let pct = 0;
  let chipTitle = "View fetch progress";

  if (state.fetchBusy && state.fetchingCompanyKey) {
    const company = state.fetchingCompanyKey.split(":").slice(1).join(":");
    metaText = company || "1 company";
    chipTitle = `View progress for ${company}`;
  } else if (summary.total > 0) {
    pct = summary.total > 0
      ? Math.min(99, Math.round((summary.current / summary.total) * 100))
      : 0;
    metaText = `${summary.current} / ${summary.total} companies`;
    chipTitle = `View fetch progress — ${summary.current} of ${summary.total} companies (${pct}%)`;
    if (summary.company) {
      companyLine = summary.company;
      chipTitle += ` · ${summary.company}`;
    }
  } else if (summary.company) {
    metaText = summary.company;
    chipTitle = `View progress for ${summary.company}`;
  } else if (summary.countryLabel) {
    metaText = summary.countryLabel;
    chipTitle = `View fetch progress for ${summary.countryLabel}`;
  } else if (summary.activityMessage) {
    metaText = summary.activityMessage.replace(/…$/, "").trim() || "Starting…";
  }

  if (meta) meta.textContent = metaText;
  if (fill) fill.style.height = `${Math.max(8, pct)}%`;
  if (companyEl) {
    if (companyLine) {
      companyEl.textContent = companyLine;
      companyEl.hidden = false;
    } else {
      companyEl.textContent = "";
      companyEl.hidden = true;
    }
  }
  chip.title = chipTitle;
  chip.setAttribute("aria-label", chipTitle);
}

