    }
  } else if (summary.company) {
    metaText = summary.company;
    chipTitle = `View progress for ${summary.company}`;
  } else if (summary.countryLabel) {
    metaText = summary.countryLabel;
    chipTitle = `View fetch progress for ${summary.countryLabel}`;
  } else if (summary.activityMessage) {
    metaText = summary.activityMessage.replace(/…$/, "").trim() || "Starting…";
  }

  if (meta) meta.textContent = metaText;
  if (fill) fill.style.height = `${Math.max(8, pct)}%`;
  if (companyEl) {
    if (companyLine) {
      companyEl.textContent = companyLine;
      companyEl.hidden = false;
    } else {
      companyEl.textContent = "";
      companyEl.hidden = true;
    }
  }
  chip.title = chipTitle;
  chip.setAttribute("aria-label", chipTitle);
}

